func TestRing_TransferKeys_NoSideEffect(t *testing.T) {
	r := NewRing(100)
	r.Add("n1")
	r.Add("n2")
	sizeBefore := r.Size()

	keys := make([]string, 50)
	for i := range keys {
		keys[i] = fmt.Sprintf("tk-%d", i)
	}
