	}
}

func TestRing_FNV_MinimalDisruption(t *testing.T) {
	r := NewRing(100)
	r.Add("s1")
	r.Add("s2")
	keys := make([]string, 1000)
	for i := range keys {
		keys[i] = fmt.Sprintf("md-%d", i)
	}
	before := make(map[string]string, len(keys))
	for _, k := range keys {
		before[k] = r.Lookup(k)
	}
	r.Add("s3")
	moved := 0
	for _, k := range keys {
		if r.Lookup(k) != before[k] {
			moved++
		}
	}
	moveRate := float64(moved) / float64(len(keys))
	if moveRate > 0.60 {
		t.Fatalf("too many keys moved (%.2f) — minimal disruption violated", moveRate)
	}
}

